export const PLANET_IN_SIGN: Record<string, Record<string, string>> = {
    Ascendant: {
        aries: "Tu arrives comme une flèche : présence directe, énergie visible, regard qui va droit au but. Les autres te perçoivent comme quelqu'un de vif et d'entreprenant, parfois d'impatient : on sent que tu n'es pas là pour attendre. Cette allure fonceuse peut masquer un intérieur plus nuancé, mais elle t'ouvre des portes : tu donnes envie d'agir. Ton défi : laisser voir aussi ta douceur, pour qu'on ne te réduise pas à ton élan.",
        taurus: "Tu arrives comme une évidence tranquille : présence posée, voix calme, quelque chose de rassurant qui donne envie de rester près de toi. Les autres te perçoivent comme fiable et ancré : on te confie spontanément ce qui est précieux. Ton abord ne laisse jamais paraître de précipitation, même quand ça bouillonne à l'intérieur. Ton défi : montrer que tu sais aussi bouger. Ta stabilité est une force, pas de la lenteur.",
        gemini: "Tu arrives par les mots : regard curieux, esprit visible, une aisance qui crée le contact en trente secondes. Les autres te perçoivent comme vif, jeune d'esprit, intéressant : celui qui pose la bonne question ou lance le trait d'humour qui détend la table. Cette allure légère peut cacher des profondeurs que peu de gens devinent. Ton défi : laisser les conversations descendre sous la surface. Tu vaux mieux que ton brio.",
        cancer: "Tu arrives sur la pointe des pieds : présence douce, réceptive, qui capte l'ambiance avant de s'avancer. Les autres te perçoivent d'abord comme attentionné et un peu réservé, puis découvrent une chaleur enveloppante une fois la confiance installée. Tu inspires la confidence sans la demander : on se livre facilement à toi. Ton défi : ne pas laisser la carapace décider à ta place. Le monde mérite de te rencontrer.",
        leo: "Tu arrives comme un lever de soleil : présence chaleureuse, naturellement remarquée, un port qui en impose sans effort. Les autres te perçoivent comme généreux et sûr de toi, même les jours où tu ne l'es pas du tout : c'est toute l'ironie de cet Ascendant. Tu réchauffes une pièce en y entrant. Ton défi : t'autoriser à paraître vulnérable. Ta couronne n'en tombera pas.",
        virgo: "Tu arrives avec discrétion et précision : présence soignée, observatrice, qui jauge la situation avant de s'engager. Les autres te perçoivent comme compétent et fiable, un brin réservé : celui qui remarque le détail que tout le monde a manqué. Ton abord modeste cache souvent bien plus de richesse qu'il n'en annonce. Ton défi : oser prendre de la place. Ta retenue est une élégance, pas une obligation.",
        libra: "Tu arrives avec grâce : présence harmonieuse, sourire facile, un art inné de mettre les autres à l'aise. Les autres te perçoivent comme charmant et diplomate : on t'invite, on te consulte, on recherche ta compagnie. Ce vernis aimable a un coût : à force de plaire, on oublie de te demander ton avis. Ton défi : afficher tes préférences. Le charme avec du caractère, c'est irrésistible.",
        scorpio: "Tu arrives avec intensité : regard qui traverse, présence magnétique, quelque chose d'indéchiffrable qui intrigue ou intimide. Les autres te perçoivent comme profond et secret : on sent qu'il se passe quelque chose sous la surface, sans savoir quoi. Tu ne laisses personne indifférent, jamais. Ton défi : laisser filtrer un peu de lumière. Ton mystère attire, mais c'est ta confiance qui attache.",
        sagittarius: "Tu arrives comme un courant d'air chaud : présence enthousiaste, franche, tournée vers l'ailleurs. Les autres te perçoivent comme optimiste et direct : celui qui élargit la conversation et redonne de l'élan à tout le monde. Ton abord généreux promet de grands horizons. Ton défi : incarner ce que tu annonces. Ton enthousiasme engage ; sois aussi celui qui reste.",
        capricorn: "Tu arrives avec gravité : présence sérieuse, posée, une réserve qui inspire d'emblée le respect. Les autres te perçoivent comme mûr et solide : on te donne des responsabilités avant même de te connaître. Cette allure austère s'adoucit magnifiquement avec les années ; c'est l'Ascendant qui embellit en vieillissant. Ton défi : laisser ton humour et ta tendresse se montrer plus tôt. La dignité n'exclut pas la légèreté.",
        aquarius: "Tu arrives comme personne d'autre : présence singulière, un regard qui semble observer le monde avec un pas de côté. Les autres te perçoivent comme original et libre : impossible de te ranger dans une case, et ça se sent tout de suite. Tu attires ceux qui cherchent de l'air. Ton défi : montrer que ta différence n'est pas une distance. On peut être unique et proche à la fois.",
        pisces: "Tu arrives comme une atmosphère : présence fluide, douce, presque insaisissable. On te sent avant de te comprendre. Les autres te perçoivent comme empathique et rêveur, mystérieusement apaisant ; chacun projette un peu son film sur toi. Cette porosité te rend attachant et difficile à cerner. Ton défi : poser tes contours. Être accueillant, oui ; devenir le miroir de tout le monde, non.",
    },

    Sun: {
        aries: "Ton identité s'est construite dans l'élan : tu existes en agissant, en osant, en ouvrant la voie. Tu as le courage des premières fois, celui qui inspire les autres même quand il te met en difficulté. Il te faut des défis pour te sentir vivant : une vie trop calme t'éteint à petit feu. Ton défi de croissance : apprendre la patience et l'endurance, pour que tes feux de paille deviennent des feux durables. Ton énergie est réelle et contagieuse ; elle rend d'autant plus si tu choisis tes batailles.",
        taurus: "Ton identité s'enracine dans le concret : tu es venu construire, stabiliser, savourer. Il y a en toi une force tranquille que rien ne presse : tu avances à ton rythme, mais tu arrives toujours. Les plaisirs simples (un repas, un jardin, un moment sans montre) ne sont pas un luxe pour toi : c'est ta façon de recharger. Tu brilles par ta fiabilité et ta capacité à faire durer ce que d'autres abandonnent. Ton défi : distinguer la fidélité à toi-même de la résistance au changement. Parfois, lâcher est la vraie force.",
        gemini: "Ton identité passe par l'esprit : comprendre, relier, raconter, c'est ta façon d'exister. Tu es plusieurs à la fois, et c'est une richesse, pas une incohérence. Quel que soit ton âge, tu restes celui qui pose des questions et fait circuler les idées. Tu t'épanouis dans l'échange, l'écriture, tout ce qui met du mouvement dans la pensée. Ton défi de croissance : choisir quelques fils conducteurs et les suivre jusqu'au bout, pour que ta polyvalence produise une œuvre au lieu de se disperser.",
        cancer: "Ton identité est tissée de sensibilité : tu te réalises en prenant soin, en créant des liens qui durent et des lieux où l'on se sent bien. Tu portes ton histoire, ta famille, tes racines dans tout ce que tu fais. Ta force, c'est cette intelligence du cœur qui devine les besoins des autres avant qu'ils ne les expriment. Ton défi : ne pas te cacher dans ta coquille quand la vie te demande de te montrer. Tu es fait pour nourrir le monde, pas seulement pour t'en protéger.",
        leo: "Le Soleil est chez lui en Lion : ton identité demande à rayonner pleinement. Tu es venu créer, exprimer, réchauffer. Il y a en toi une générosité naturelle et un besoin légitime d'être reconnu pour ce que tu es. Quand tu assumes ta lumière, tu tires tout ton entourage vers le haut. Quand tu doutes d'elle, tu la mendies dans le regard des autres, et c'est là que ça se complique. Ton défi de croissance : briller sans dépendre des applaudissements, donner sans attendre le retour. Ta noblesse est réelle ; la sincérité la rend irrésistible.",
        virgo: "Ton identité se réalise dans le travail bien fait : tu es venu affiner, servir, rendre le monde plus juste et plus fonctionnel. Ta lumière est discrète mais indispensable : tu es celui sans qui rien ne marche vraiment. L'intelligence du détail, l'humilité, le souci des autres : voilà ton éclat. Ton défi de croissance : cesser de te juger plus durement que tu ne jugerais quiconque. Ta valeur ne dépend pas de ta perfection ; tu as le droit d'être fier de toi avant que tout soit impeccable.",
        libra: "Ton identité se construit dans la relation : tu te découvres à travers les autres, dans l'art du lien, de l'harmonie, de la justice. Tu as une élégance naturelle : dans les gestes, les mots, la façon de mettre les gens à l'aise. Ton talent : voir tous les points de vue et ramener de l'entente là où il y avait de la discorde. Ton défi de croissance : exister aussi par toi-même, oser déplaire, trancher. Ta quête d'équilibre n'aura de sens que si toi aussi tu pèses dans la balance.",
        scorpio: "Ton identité s'est forgée dans l'intensité : tu ne sais pas vivre à moitié. Il y a en toi une profondeur magnétique, un regard qui perce les façades, une capacité à ressortir de tes crises plus fort qu'avant. Tu es venu transformer : toi d'abord, et souvent les autres à ton contact. Ta puissance est réelle, et elle peut faire peur, à commencer par toi. Ton défi de croissance : faire confiance, te dévoiler, mettre ton intensité au service de la création plutôt que du contrôle. Ta lumière naît précisément de tes descentes dans l'ombre.",
        sagittarius: "Ton identité respire dans l'horizon : tu es venu explorer, comprendre le monde en grand, transmettre ce que tu découvres. Il y a en toi un optimisme de fond, une foi en la vie qui survit aux déceptions et redonne du courage aux autres. Tu brilles quand tu as une quête : un voyage, une cause, une vérité à poursuivre. Ton défi de croissance : incarner tes belles idées dans le quotidien, tenir tes promesses à hauteur de tes enthousiasmes. Ta sagesse sera complète le jour où elle saura aussi rester.",
        capricorn: "Ton identité se construit comme on gravit une montagne : par étapes, avec sérieux, en visant haut. Tu es venu bâtir quelque chose qui dure : une œuvre, une position, une famille solide. Ta force, c'est cette maturité précoce, cette capacité à porter des responsabilités qui ferait plier d'autres épaules. Le respect, tu ne le demandes pas : tu le gagnes. Ton défi de croissance : ne pas confondre ta valeur avec tes accomplissements, et laisser la douceur entrer dans la forteresse. Le sommet est plus beau quand on peut le partager.",
        aquarius: "Ton identité s'affirme dans la différence : tu es venu penser autrement, libérer, inventer. Il y a en toi un mélange rare de recul et d'idéalisme : tu vois la société de l'extérieur, ce qui te permet d'imaginer ce qu'elle pourrait devenir. Ton originalité n'est pas une pose : c'est ta nature, et le monde a besoin de gens comme toi pour ne pas se figer. Ton défi de croissance : laisser l'émotion et l'intime avoir leur place dans ta vie de visionnaire. Être libre, c'est aussi être libre d'être touché.",
        pisces: "Ton identité est fluide, poreuse, reliée à plus grand que toi : tu es venu ressentir, imaginer, consoler. Il y a en toi une compassion sans bornes et un accès direct à l'invisible : rêves, art, spiritualité, intuition. Tu brilles partout où il faut de l'âme, précisément parce que tu ne joues pas de rôle. Ton défi de croissance : te donner des contours (des limites, des choix, un cap) pour que ta sensibilité serve ta vie au lieu de la submerger. Le monde a besoin de ta lumière douce, pas de ton sacrifice.",
    },

    Moon: {
        aries: "Tes émotions sont immédiates et entières : tout se vit à chaud, tout de suite. La colère monte vite mais retombe aussi vite ; tu ne sais pas bouder longtemps. Pour te sentir en sécurité, paradoxalement, il te faut de l'action : bouger, décider, régler les choses sans attendre. Ce qui te fait vraiment souffrir, c'est d'attendre sans pouvoir rien faire. Enfant, tu as peut-être dû te débrouiller émotionnellement seul, d'où ce réflexe d'indépendance. Ton apaisement passe par le corps : dépense-toi, et le calme revient de lui-même.",
        taurus: "Tes émotions cherchent la stabilité : il te faut des rituels, du confort, des choses qui ne changent pas pour te sentir en paix. La Lune est exaltée en Taureau : ton monde intérieur est naturellement solide, et tu es souvent le port d'attache de ton entourage. La douceur matérielle te régule concrètement : un bon repas, un plaid, de la musique, un jardin. Ton défi émotionnel : accepter les changements imposés sans les vivre comme des menaces. Ta sécurité profonde ne réside pas dans ce que tu possèdes, mais dans ta capacité à savourer.",
        gemini: "Tes émotions passent par les mots : tu as besoin d'en parler pour comprendre ce que tu ressens. Le silence prolongé t'angoisse plus que le conflit. Ton monde intérieur est vif et changeant : plusieurs humeurs peuvent se succéder dans la même heure, et c'est normal chez toi. Tu te ressources dans l'échange, la lecture, la variété. Ton défi émotionnel : descendre du mental au ressenti. Nommer une émotion ne suffit pas toujours à la traverser ; parfois il faut juste la laisser être là, sans commentaire.",
        cancer: "La Lune est chez elle en Cancer : ton monde émotionnel est vaste, profond, réceptif. Tu ressens tout : tes émotions et celles des autres, parfois sans pouvoir les distinguer. Ton besoin fondamental : un nid, des liens fidèles, la permission d'être sensible sans être jugé. Tu prends soin des gens naturellement, quelle que soit ta façon de l'exprimer. Ton défi émotionnel : ne pas te laisser gouverner par tes marées intérieures, ni ressasser les blessures anciennes. Apprends à te donner à toi-même la tendresse que tu offres si bien.",
        leo: "Tes émotions ont besoin de reconnaissance : tu te sens aimé quand on te voit, quand on te célèbre, quand ta présence compte. Ton cœur est chaleureux et théâtral au sens noble : tu vis tes joies et tes peines en grand. Tu te régules par la création et le jeu : ce qui te rend fier te répare. Ton défi émotionnel : ne pas dépendre de l'admiration pour te sentir en sécurité, et accepter les moments où tu n'es pas au centre. Tu restes précieux même dans l'ombre ; c'est là que ça se prouve.",
        virgo: "Tes émotions passent par le filtre de l'analyse : face à un trouble, ton réflexe est de comprendre, trier, résoudre. Prendre soin des détails du quotidien est ta façon de te rassurer, et de dire je t'aime. Un environnement ordonné apaise directement ton système nerveux : range ton bureau, et ta tête suit. Ton défi émotionnel : tolérer ce qui ne se répare pas, chez toi comme chez les autres, sans te sentir en faute. Ton anxiété diminuera le jour où tu accepteras qu'être utile n'est pas une condition pour être aimé.",
        libra: "Tes émotions cherchent l'harmonie : le conflit te coûte physiquement, la discorde te vide. Tu te sens en sécurité dans le lien : à deux, accompagné, en bonne entente avec ton entourage. Ta douceur n'est pas une façade : c'est ton climat intérieur naturel, et tu sais l'installer autour de toi. Ton défi émotionnel : reconnaître tes propres besoins au lieu de t'accorder automatiquement à ceux des autres. La paix qui te fait taire n'est pas la paix. Une relation solide peut survivre à ton désaccord ; c'est même à ça qu'on la reconnaît.",
        scorpio: "Tes émotions sont des profondeurs marines : intenses, secrètes, entières. Tu ne ressens jamais à moitié : tu aimes, tu souffres, tu désires avec une puissance que tu as appris tôt à dissimuler. Ta sécurité passe par la loyauté absolue : trahir ta confiance, c'est la perdre. Tu as un don pour percevoir ce que les autres cachent, même sous les sourires. Ton défi émotionnel : ne pas transformer chaque blessure en forteresse ou en rancune silencieuse. Ta sensibilité extrême est une force de renaissance : ce qui te traverse te transforme.",
        sagittarius: "Tes émotions ont besoin d'espace : quand ça va mal, ton réflexe est de partir. Physiquement, ou dans un projet, un ailleurs, une perspective plus vaste. L'optimisme est ta régulation naturelle : tu as un don pour rebondir et pour redonner de l'élan aux autres. Ce qui t'empoisonne : l'enfermement, les drames qui s'éternisent, les liens qui étouffent. Ton défi : rester présent quand l'émotion est inconfortable, au lieu de la fuir par le haut. Certaines choses ne se règlent qu'en les traversant, pas en les survolant.",
        capricorn: "Tes émotions sont pudiques : tu as appris tôt à les contenir, peut-être parce qu'il fallait être fort, responsable, adulte avant l'heure. Ta sécurité passe par la maîtrise : de ta vie, de tes engagements, de ce qu'on peut attendre de toi. Tu dis ton attachement par des actes fiables (être là, tenir parole) plutôt que par des mots tendres. Ton défi émotionnel : t'autoriser la vulnérabilité, qui n'est pas une faiblesse mais une porte. Ceux qui t'aiment n'attendent pas ta performance : ils t'attendent toi, y compris fatigué, y compris ému.",
        aquarius: "Tes émotions passent d'abord par la distance : face à un trouble, tu prends du recul, tu observes, tu analyses, comme si tu regardais ton propre cœur depuis un satellite. Ce détachement est précieux dans les crises, mais il peut te couper de ton ressenti. Tu as besoin de liberté affective : les liens fusionnels t'étouffent, et l'amitié est ton langage amoureux. Ton défi émotionnel : redescendre dans ton corps et laisser l'émotion t'atteindre en direct. Être touché n'est pas être piégé.",
        pisces: "Tes émotions sont un océan sans digues : tu ressens tout, celles des autres comprises, souvent avant qu'ils ne les remarquent eux-mêmes. Cette porosité fait de toi un être d'une compassion rare, et facilement submergé : une ambiance lourde peut te gâcher une journée. Tu te ressources dans le rêve, la musique, l'eau, le silence. Ton défi émotionnel : distinguer ce qui t'appartient de ce que tu éponges, et t'accorder des sas de décompression sans culpabilité. Ta sensibilité est un don, à condition de ne pas t'y noyer.",
    },

    Mercury: {
        aries: "Ton esprit fonctionne à l'étincelle : tu comprends vite, tu décides vite, tu dis les choses sans détour. Ta parole est directe, parfois tranchante : c'est sa force et son risque. Tu excelles dans le débat, l'urgence, les situations où il faut trancher pendant que d'autres délibèrent encore. Les réunions qui tournent en rond te rendent fou. Ton défi mental : écouter jusqu'au bout avant de répondre, et vérifier avant d'affirmer. Ta vivacité est une arme redoutable quand elle accepte de viser avant de tirer.",
        taurus: "Ton esprit travaille comme la terre : lentement, sûrement, profondément. Il te faut du temps pour intégrer une idée, mais une fois comprise, elle est à toi pour toujours. Ta parole est posée, concrète, fiable : on te croit, parce que tu ne dis rien que tu n'aies vérifié. Tu penses mieux en marchant, en faisant, en manipulant du concret. Ton défi mental : rester ouvert aux idées qui bousculent tes conclusions, même après les avoir arrêtées. La lenteur est ta force ; l'entêtement en est la caricature.",
        gemini: "Mercure est chez lui en Gémeaux : ton esprit est son royaume. Rapide, agile, insatiable, tu absorbes l'information de partout et tu la relies comme personne. La conversation est ton sport, l'humour ton outil, la curiosité ton moteur. Tu peux apprendre n'importe quoi ; le défi est de choisir quoi. Ton risque : la dispersion, le survol, le mental qui ne s'éteint jamais, même la nuit. Ta croissance passe par la profondeur : choisis quelques sujets qui te tiennent aux tripes, et donne-leur les années qu'ils méritent.",
        cancer: "Ton esprit pense avec le cœur : tu mémorises par l'émotion, tu comprends par l'empathie, tu communiques par la nuance. Ta parole sait envelopper : tu trouves d'instinct les mots qui rassurent. Ta mémoire est phénoménale pour tout ce qui a compté émotionnellement : les dates, les visages, les phrases dites il y a dix ans. Ton défi mental : ne pas prendre chaque remarque comme une attaque personnelle, et distinguer intuition et projection. En sécurité, ton intelligence sensible comprend ce que la logique seule ne verra jamais.",
        leo: "Ton esprit pense en grand et parle pour être entendu : tu as le sens de la formule, du récit, de la mise en scène des idées. Convaincre te vient naturellement : il y a du soleil dans ta parole, une chaleur qui embarque. Tu apprends mieux quand tu es fier de ce que tu fais, et tu transmets avec générosité. Ton défi mental : accepter la contradiction sans la vivre comme un affront, et laisser les autres briller aussi dans la conversation. Ta parole est faite pour éclairer, pas pour régner.",
        virgo: "Mercure est chez lui en Vierge : ton esprit est un instrument de précision. Tu vois le détail que tout le monde a manqué, la faille du raisonnement, le mot exact. Analyser, trier, améliorer : c'est ta respiration mentale. Ta parole est mesurée, utile, sans esbroufe : tu préfères être juste plutôt que brillant. Ton défi mental : ne pas laisser l'esprit critique devenir autocritique permanente, ni le perfectionnisme retarder indéfiniment tes conclusions. Ton intelligence est faite pour servir, pas pour te condamner.",
        libra: "Ton esprit pèse tout : chaque question a pour toi deux faces, et tu les vois toutes les deux. C'est ta finesse, et ton tourment. Tu excelles dans la diplomatie, la médiation, l'art de dire les choses difficiles sans blesser. Ta parole est élégante, ton écoute réelle. Le débat t'intéresse pour comprendre, pas pour gagner. Ton défi mental : trancher. À force de voir tous les points de vue, tu risques de ne plus connaître le tien. Décider, c'est renoncer, et c'est la seule façon d'avancer.",
        scorpio: "Ton esprit est un scalpel : il va droit sous la surface, détecte le non-dit, comprend les motivations cachées. On ne te ment pas facilement. Tu parles peu mais juste : chaque mot est pesé, et tes silences en disent autant que tes phrases. Tu es fait pour l'enquête, la psychologie, la stratégie, tout ce qui demande de creuser. Ton défi mental : ne pas tomber dans le soupçon systématique, ni utiliser ta lucidité comme une arme. Ta parole a du pouvoir : ce qui est dit ne se retire pas.",
        sagittarius: "Ton esprit voit la carte avant le terrain : tu penses en grandes synthèses, en visions d'ensemble, en rapprochements que d'autres trouvent audacieux. Tu apprends par l'expérience et l'exploration plus que par les manuels. Ta parole est franche, enthousiaste, contagieuse : tu es un conteur-né et un professeur dans l'âme. Ton défi mental : soigner les détails qui te semblent secondaires, et vérifier tes certitudes. Ta conviction peut te faire prendre une intuition pour un fait. Vise juste, pas seulement loin.",
        capricorn: "Ton esprit construit : chaque idée est évaluée à l'aune de son utilité, de sa solidité, de son coût réel. Tu penses en plans et en étapes : le flou t'agace, les promesses vagues te laissent froid. Ta parole est sobre et fait autorité : tu ne dis que ce que tu peux tenir. Ton humour, sec et précis, surprend toujours ceux qui te croyaient austère. Ton défi mental : laisser de la place à l'imprévu et aux idées non rentables. Certaines pensées inutiles sont celles qui changent une vie.",
        aquarius: "Ton esprit vit dans le futur : tu vois les systèmes, les schémas, les possibilités que le présent n'imagine pas encore. Penser hors du cadre n'est pas un exercice pour toi : c'est ton état par défaut. Les idées neuves, la science, les utopies concrètes t'attirent. Ta parole est originale, parfois déroutante, jamais banale. Ton défi mental : rester compréhensible pour ceux qui pensent autrement, et accepter que les idées justes aient besoin de temps et de pédagogie pour être entendues.",
        pisces: "Ton esprit fonctionne par vagues : intuitions, images, associations. Tu comprends d'un bloc ce que d'autres démontent pièce par pièce. La logique linéaire n'est pas ton chemin naturel, et c'est très bien : ton intelligence est poétique, empathique, imaginative. Tu lis entre les lignes, tu entends ce qui n'est pas dit. Ton défi mental : traduire tes intuitions en mots clairs et vérifier qu'on t'a compris, car ton flou peut créer des malentendus. Ton imaginaire est une source ; donne-lui des canaux.",
    },

    Venus: {
        aries: "Tu aimes comme on part en conquête : coup de foudre, élan direct, désir assumé. La séduction est pour toi une aventure : tu préfères faire le premier pas plutôt que d'attendre en espérant. Ce qui t'attire : l'intensité des débuts, la franchise, quelqu'un qui te résiste un peu. Ce qui te lasse : la routine, les non-dits, la tiédeur. Ton défi amoureux : entretenir la flamme après la conquête, car aimer se prouve aussi dans la durée. Ta spontanéité est rafraîchissante ; ne la laisse jamais devenir de l'impatience du cœur.",
        taurus: "Vénus est chez elle en Taureau : tu aimes avec les sens et avec constance. Le toucher, les repas partagés, la présence physique : ton amour passe par le corps et le concret, pas par les grandes déclarations. Tu offres une fidélité rare et tu attends la même. Ce qui t'attire : la douceur, la stabilité, une beauté naturelle. Ton défi amoureux : distinguer aimer et posséder. L'autre n'est pas un acquis, et la jalousie abîme ce qu'elle prétend protéger. Ton amour est un jardin : il fleurit par le soin, pas par la clôture.",
        gemini: "Tu aimes d'abord par l'esprit : une conversation brillante te séduit plus qu'un physique parfait. Il te faut de la légèreté, du jeu, de la variété : quelqu'un qui garde un peu de mystère, avec qui on ne s'ennuie jamais. Ton affection s'exprime par les mots, les messages, l'humour complice. Ce qui t'éteint : la lourdeur, la possessivité, le sérieux permanent. Ton défi amoureux : comprendre que l'engagement n'est pas une prison. On peut être libre à deux. La profondeur n'est pas l'ennemie de la légèreté : elle en est le socle.",
        cancer: "Tu aimes en profondeur : ce que tu cherches n'est pas une histoire mais un foyer. Quelqu'un avec qui construire un monde à soi, fait de rituels, de tendresse et de souvenirs partagés. Ton attachement est total : tu prends soin, tu protèges, tu nourris. Ta sensibilité capte chaque variation d'humeur de l'autre, parfois trop. Ton défi amoureux : exprimer tes besoins directement au lieu d'espérer qu'on les devine, et ne pas te réfugier dans ta coquille au premier froid. Ton cœur est un refuge : offre-le à qui en connaît la valeur.",
        leo: "Tu aimes en grand : ton cœur est généreux, loyal, spectaculaire. Aimer, pour toi, c'est célébrer l'autre (cadeaux, attentions, fierté affichée) et être célébré en retour. Tu as besoin d'admirer ton partenaire et de te sentir unique à ses yeux : l'amour tiède n'est pas de l'amour. Ce qui te blesse le plus : l'indifférence, être considéré comme acquis. Ton défi amoureux : aimer aussi dans les jours ordinaires, quand il n'y a ni public ni éclat. Le grand amour se prouve dans les petites attentions répétées.",
        virgo: "Tu aimes par les actes : préparer le café, faciliter la journée de l'autre, penser aux détails qui adoucissent la vie. Voilà tes déclarations. Les grands mots te gênent ; la constance discrète est ta signature affective. Tu es attentif, dévoué, d'une fiabilité précieuse. Ce qui t'attire : l'intelligence, la propreté du cœur, quelqu'un qui se tient. Ton défi amoureux : ne pas transformer l'amour en liste de choses à corriger, ni critiquer ce que tu pourrais simplement accueillir. Et surtout : te laisser aimer aussi, imparfait, c'est-à-dire réel.",
        libra: "Vénus est chez elle en Balance : aimer est ton art. Tu as le génie du lien : l'attention à l'autre, le raffinement, cette grâce qui transforme un dîner ordinaire en moment suspendu. Tu cherches un vrai partenaire : quelqu'un avec qui penser, avancer, s'accorder. La beauté te nourrit, littéralement. Ton défi amoureux : rester toi-même dans le couple. À force de t'adapter, tu risques de disparaître dans le nous. Le conflit évité n'est pas résolu : ose le désaccord, ton harmonie n'en sera que plus vraie.",
        scorpio: "Tu aimes absolument : fusion, loyauté totale, désir profond. Les demi-mesures affectives te sont physiquement impossibles. L'amour est pour toi une transformation : tu veux toucher l'âme de l'autre, pas seulement sa main. Cette intensité est magnétique, et exigeante. Ce qui te détruit : la trahison, même minuscule. Ton défi amoureux : faire confiance sans tester, aimer sans surveiller. La vulnérabilité que tu redoutes est précisément ce qui rend l'intimité possible. Ton amour est une force rare : offre-le, ne l'impose pas.",
        sagittarius: "Tu aimes en mouvement : ton cœur a besoin d'un compagnon d'aventure plus que d'un gardien de foyer. Rire ensemble, explorer ensemble, grandir ensemble : voilà ton programme amoureux. Tu offres l'enthousiasme, la franchise, une foi contagieuse en l'avenir du lien. Ce qui t'étouffe : la jalousie, les comptes à rendre, le quotidien qui rétrécit. Ton défi amoureux : comprendre que la liberté se construit aussi dans l'engagement. Le bon lien n'est pas celui qui retient ; mais pour le vérifier, il faut rester assez longtemps.",
        capricorn: "Tu aimes sérieusement : pour toi, l'amour est un engagement qui se prouve dans le temps, pas une émotion qui se déclare. Tu es lent à ouvrir ton cœur (chaque étape est pesée), mais ta parole donnée est du granit. Tu montres ton attachement en construisant : une vie, une sécurité, des projets. Ce qui t'attire : la fiabilité, l'ambition, une forme de dignité. Ton défi amoureux : laisser la tendresse s'exprimer sans attendre le moment parfait. La vulnérabilité n'entame pas ta solidité ; elle la rend habitable.",
        aquarius: "Tu aimes librement : l'amitié est le socle de tes amours. Il te faut d'abord un complice, un égal, quelqu'un qui respecte ton espace autant que tu respectes le sien. Les conventions amoureuses te laissent sceptique : tu inventes ta propre façon d'être en couple. Ton affection est loyale mais peu démonstrative, ce qui peut dérouter. Ton défi amoureux : laisser l'intimité émotionnelle exister. La proximité du cœur n'est pas une aliénation. Aimer vraiment quelqu'un ne t'enlèvera pas à toi-même : c'est une liberté de plus.",
        pisces: "Vénus est exaltée en Poissons : tu aimes sans limites, avec une tendresse, une dévotion et une capacité de pardon qui touchent au sacré. Tu ressens l'autre de l'intérieur, tu aimes jusqu'à ses blessures. Le romantisme n'est pas un décor chez toi : c'est une vision du monde. Ton défi amoureux : aimer la personne réelle plutôt que le rêve que tu projettes sur elle, et garder des limites. Te sacrifier n'est pas aimer plus fort. Ton cœur est immense : il mérite quelqu'un qui en prenne soin, pas quelqu'un qui s'y noie.",
    },

    Mars: {
        aries: "Mars est chez lui en Bélier : ton énergie est pure, directe, immédiate. Tu passes à l'action pendant que d'autres en sont encore à l'idée : c'est ta grande force. Ta colère est franche : elle explose, puis c'est fini, sans rancune. Tu es fait pour les défis, les débuts, les situations qui exigent du cran. Ton défi : l'endurance. Ton feu démarre fort mais peut s'essouffler dès que la nouveauté retombe. Apprends à doser tes assauts : un guerrier qui gère son souffle gagne des guerres, pas seulement des batailles.",
        taurus: "Ton énergie est celle du bulldozer tranquille : lente à démarrer, impossible à arrêter. Tu n'agis que quand tu es sûr, mais alors rien ne te fait dévier : ta ténacité use tous les obstacles. Ta colère est rare et précédée d'une longue patience ; quand elle éclate, elle marque les esprits. Ton désir est sensuel, constant, ancré dans le corps. Ton défi : la souplesse. Savoir changer de route n'est pas trahir son objectif. Ta force tranquille devient redoutable quand elle cesse de confondre persévérance et obstination.",
        gemini: "Ton énergie est mentale : tu te bats avec les mots, les idées, l'agilité. Ta vivacité te permet de mener plusieurs fronts à la fois : c'est ton talent, et ton piège, car l'énergie dispersée perd sa force de frappe. Tu excelles dans le débat, la répartie, la négociation rapide. Ta colère est verbale : tes mots peuvent couper plus fort que tu ne le crois. Ton défi : finir. Choisis moins de combats et mène-les au bout. Ton arme secrète : personne ne pense plus vite que toi sous pression.",
        cancer: "Ton énergie est indirecte mais profonde : tu n'attaques pas de front, tu protèges. Menace quelqu'un que tu aimes, et on découvrira une férocité que personne ne soupçonnait. Ta colère, elle, a tendance à rentrer : elle rumine, s'accumule, puis déborde d'un coup. Ton défi : exprimer le désaccord à chaud, calmement, au lieu de le laisser fermenter des semaines. Ton action est puissante quand elle a une raison affective : tu ne te bats jamais mieux que pour un foyer, une famille, une cause qui touche le cœur.",
        leo: "Ton énergie est solaire : tu agis avec panache, courage et le sens du geste qui marque. Tu ne fais rien à moitié : chaque projet porte ta signature, chaque combat doit être digne de toi. Ta colère est spectaculaire mais noble : tu attaques de face, jamais dans le dos. Tu es fait pour mener, inspirer, défendre les tiens avec éclat. Ton défi : agir aussi quand personne ne regarde, et servir la cause plutôt que ton image. Ta fierté est un moteur splendide tant qu'elle ne devient pas le but.",
        virgo: "Ton énergie est chirurgicale : tu agis avec méthode, précision et une efficacité redoutable. Pas de gestes inutiles : tu analyses, tu planifies, tu exécutes proprement. Ton courage est discret : c'est celui du travail bien fait, de la persévérance dans le détail, du service rendu sans bruit. Ta colère sort en critique pointue plutôt qu'en éclat. Ton défi : accepter d'agir avant que les conditions soient parfaites. L'analyse sans fin est une forme de fuite. Fait vaut mieux que parfait, surtout pour toi.",
        libra: "Ton énergie s'exprime dans le lien : tu agis mieux à deux, en équipe, en alliance. Le conflit direct te coûte : ton talent est de désamorcer, négocier, gagner sans guerre. C'est une vraie force de stratège, pas une faiblesse. Ta colère, faute de sortir, se retourne parfois contre toi. Ton défi : assumer l'affrontement quand il est juste. Ne pas choisir, c'est aussi un choix, et la paix achetée par ton silence se paie avec intérêts. Ta combativité élégante est rare : ose t'en servir pour toi.",
        scorpio: "Mars est puissant en Scorpion, son domicile traditionnel : ton énergie est stratégique, profonde, impossible à arrêter. Tu n'agis jamais à moitié : quand tu veux quelque chose, tu creuses, tu attends, tu persévères là où tous abandonnent. Ta colère est froide : elle ne crie pas, elle n'oublie pas. Ton désir est intense, magnétique, total. Ton défi : ne pas laisser le contrôle et la rancune consumer ton énergie de l'intérieur. Ta vraie puissance n'est pas de détruire l'obstacle, mais de te transformer jusqu'à ce qu'il ne compte plus.",
        sagittarius: "Ton énergie a besoin d'un horizon : tu te bats pour des causes, des convictions, des aventures plus grandes que toi. L'enthousiasme est ton carburant : tu entraînes les autres par ta foi plus que par tes ordres. Tu agis en grand, parfois sans mesurer la logistique. Ta colère est explosive et morale : l'injustice te met en mouvement immédiatement. Ton défi : l'engagement dans la durée. Tes élans magnifiques doivent apprendre à survivre à l'ennui des étapes intermédiaires. Vise loin, mais équipe-toi pour la distance.",
        capricorn: "Mars est exalté en Capricorne : ton énergie est au sommet de sa maturité. Tu agis avec discipline, stratégie et une endurance exceptionnelle : les objectifs à dix ans ne te font pas peur, ils te structurent. Ta force est froide, méthodique : tu gravis pendant que d'autres s'agitent. Ta colère est contenue, transformée en détermination silencieuse. Ton défi : ne pas sacrifier ta vitalité au devoir. Le repos fait partie de la stratégie. Ton ambition est saine tant qu'elle sert une vie, pas l'inverse.",
        aquarius: "Ton énergie se mobilise pour des idées : tu te bats contre les injustices, les systèmes figés, les évidences que personne ne questionne. Ta manière d'agir est imprévisible : tu déroutes l'adversaire en ne faisant jamais ce qu'on attend. En équipe, tu es le stratège original, celui qui trouve l'angle que personne n'a vu. Ta colère est froide et argumentée. Ton défi : ancrer tes révolutions dans des actions concrètes et suivies. L'idée géniale sans exécution reste une conversation. Ta rébellion mérite mieux : des résultats.",
        pisces: "Ton énergie fonctionne par vagues : des périodes d'élan inspiré alternent avec des phases de retrait nécessaires. Tu n'agis pas contre : tu contournes, tu t'adaptes, tu passes là où l'eau passe. Ta force est invisible : l'intuition du bon moment, la persévérance douce, le courage de la compassion. La confrontation directe te vide. Ton défi : défendre tes intérêts aussi clairement que tu défends ceux des autres, et transformer tes rêves en gestes datés dans l'agenda. Ton action inspirée peut soulever des montagnes, à condition de commencer.",
    },

    Jupiter: {
        aries: "Ta croissance passe par l'audace : la vie te récompense chaque fois que tu oses, que tu prends l'initiative, que tu te lances sans garantie. Ta foi naturelle : croire en ton élan. Tu inspires les autres par ton courage d'ouvrir des voies : entrepreneur, pionnier, premier de cordée dans l'âme. Ton excès possible : la précipitation qui gaspille les chances, et l'ego qui confond confiance et toute-puissance. Ta sagesse grandit quand ton audace se met au service de quelque chose qui te dépasse.",
        taurus: "Ta croissance passe par la patience : tu construis ton abondance comme un verger. Tu plantes, tu soignes, tu récoltes. Tu as un vrai talent pour faire fructifier : l'argent, les projets, les plaisirs de la vie. Ta foi naturelle : la confiance dans le temps long. Ton excès possible : accumuler pour te rassurer, et confondre avoir et être. Ta sagesse grandit quand tu comprends que la vraie richesse est ta capacité à savourer, et à partager la récolte.",
        gemini: "Ta croissance passe par la connaissance : chaque rencontre, chaque livre, chaque conversation élargit ton monde. Tu as le don de rendre les choses claires, de connecter les gens et les idées, de faire circuler ce que tu apprends : enseignant, passeur, traducteur dans l'âme. Ta foi naturelle : la curiosité. Ton excès possible : savoir un peu de tout sans habiter aucun savoir. Ta sagesse grandit quand tes mille curiosités convergent vers une compréhension qui a du corps, et que ton savoir devient transmission.",
        cancer: "Jupiter est exalté en Cancer : ta croissance passe par le cœur. Tu t'épanouis en nourrissant : une famille, une équipe, un lieu où les gens se sentent accueillis. Ta générosité émotionnelle est immense et te revient multipliée : on se souvient toute une vie de ceux qui nous ont fait nous sentir chez nous. Ta foi naturelle : les racines et la bienveillance. Ton excès possible : materner jusqu'à étouffer, donner pour retenir. Ta sagesse grandit quand ton foyer devient assez vaste pour accueillir sans capturer.",
        leo: "Ta croissance passe par la création : tu es fait pour voir grand, exprimer, célébrer. Ta générosité attire la lumière et les opportunités. Quand tu crois en toi, les portes s'ouvrent ; ton enthousiasme est littéralement contagieux. Ta foi naturelle : la vie est une scène où chacun mérite son moment. Ton excès possible : la démesure, le besoin de toujours plus de reconnaissance, la confiance qui vire à l'arrogance. Ta sagesse grandit quand ta lumière sert à éclairer les autres autant que toi-même.",
        virgo: "Ta croissance passe par le service : tu t'élèves en te rendant utile, en perfectionnant, en résolvant des problèmes concrets. Ton abondance vient du travail bien fait : chez toi, la qualité finit toujours par payer. Ta foi naturelle : les petits pas qui, accumulés, déplacent des montagnes. Ton excès possible : l'exigence qui rétrécit la vision, et le doute qui n'ose pas ouvrir quand la chance sonne à la porte. Ta sagesse grandit quand tu acceptes que l'imperfection fait partie de l'abondance, et que tu mérites ta part de la récolte.",
        libra: "Ta croissance passe par les autres : les partenariats, les alliances, les rencontres décisives. Ta chance a presque toujours un visage. Tu as le don de créer des ponts, d'arrondir les angles, de faire coopérer des mondes qui s'ignoraient. Ta foi naturelle : la justice et la beauté du lien. Ton excès possible : dépendre de l'approbation, dire oui à tout le monde jusqu'à te perdre. Ta sagesse grandit quand tu comprends que le meilleur partenariat commence avec toi-même. Les autres viennent enrichir, pas compléter.",
        scorpio: "Ta croissance passe par les profondeurs : tes plus grandes expansions naissent de tes crises. Là où d'autres restent en surface, tu creuses (psychologie, mystères, vérités enfouies, ressources cachées) et tu en remontes des trésors. Ta foi naturelle : la capacité de l'être humain à renaître. Ton excès possible : l'intensité qui dramatise tout, et le pouvoir qui grise. Ta sagesse grandit quand tu utilises ta compréhension des zones d'ombre pour guérir : toi d'abord, les autres ensuite. Tu es fait pour transformer le plomb en or.",
        sagittarius: "Jupiter est chez lui en Sagittaire : ta croissance est ta nature même. Voyages, études, spiritualité, grandes causes : tout ce qui élargit l'horizon te nourrit et te réussit. Ton optimisme est une force massive : il soulève les autres et attire les opportunités comme un aimant. Ta foi naturelle : la vie a un sens, et il est bon. Ton excès possible : le trop. Trop promettre, trop embrasser, trop enseigner sans avoir vécu. Ta sagesse grandit quand ta quête d'absolu accepte de s'incarner dans l'ici et maintenant.",
        capricorn: "Ta croissance passe par la maîtrise : tu grandis lentement mais pour de bon. Chaque acquis est consolidé avant de passer au suivant. Ta chance a la forme du travail : elle vient par la réputation, la fiabilité, l'excellence reconnue. Ta foi naturelle : ce qui est bâti sérieusement finit par porter. Ton excès possible : le pessimisme qui rationne l'enthousiasme, et l'ambition qui oublie de profiter du chemin. Ta sagesse grandit quand tu t'autorises à célébrer chaque palier. L'abondance se gravit, mais elle se goûte en route.",
        aquarius: "Ta croissance passe par l'originalité : tes plus belles opportunités viennent de là où personne ne regarde. Idées d'avance, réseaux atypiques, causes collectives. Tu grandis en libérant : toi-même d'abord, puis les autres, des cadres devenus trop étroits. Ta foi naturelle : le progrès, l'humanité, le futur. Ton excès possible : l'utopie qui méprise le présent, et la rébellion par principe qui gaspille ton crédit. Ta sagesse grandit quand tes visions prennent des formes concrètes que le plus grand nombre peut habiter.",
        pisces: "Ta croissance passe par le don : plus tu offres (compassion, art, présence), plus la vie te rend, par des chemins qui défient la logique. Ta chance est mystérieuse : intuitions justes, coïncidences opportunes, protections invisibles. Ta foi naturelle : quelque chose de plus grand nous porte. Ton excès possible : la fuite dans le rêve, le sacrifice sans discernement, la confiance accordée à qui ne la mérite pas. Ta sagesse grandit quand ta spiritualité garde les pieds sur terre : inspiré mais lucide, généreux mais pas dupe.",
    },

    Saturn: {
        aries: "Ta leçon de vie touche l'affirmation : oser, décider, prendre ta place. Rien de tout cela ne t'a été donné d'office. Jeune, tu as peut-être douté de ton droit d'agir, freiné ton élan, ou au contraire foncé pour masquer la peur. Saturne ici forge un courage adulte : réfléchi, endurant, incassable. Avec les années, tu deviens celui qui ose juste : ni témérité, ni paralysie. Ta maîtrise finale : une volonté qui n'a plus rien à prouver, seulement à accomplir.",
        taurus: "Ta leçon de vie touche la sécurité : l'argent, la stabilité, la confiance dans le lendemain. Autant de terrains où rien ne t'a semblé garanti. Tu as peut-être connu la peur du manque, réelle ou intérieure, celle qui pousse à tout contrôler. Saturne ici t'apprend à construire une sécurité vraie : sobre, solide, qui ne dépend pas des à-coups du sort. Avec le temps, tu deviens un bâtisseur de patrimoine, au sens large : ce que tu possèdes vraiment, c'est ce que tu as bâti en toi.",
        gemini: "Ta leçon de vie touche la parole et la pensée : on t'a peut-être fait douter de ton intelligence, coupé la parole, ou pris tes mots à la légère. D'où une prudence à t'exprimer, un besoin de tout vérifier avant de dire. Saturne ici forge un esprit rigoureux, précis, dont chaque affirmation a du poids : l'inverse du bavardage. Avec les années, ta parole devient une référence : lente à venir, impossible à contester. Ta maîtrise finale : penser librement et solidement, sans plus t'excuser de réfléchir à ton rythme.",
        cancer: "Ta leçon de vie touche l'intime : la famille, les racines, le droit d'avoir des besoins émotionnels. Tu as peut-être manqué de chaleur, ou dû devenir adulte trop tôt. D'où cette difficulté à demander du réconfort, cette pudeur du cœur. Saturne ici t'apprend à construire toi-même le foyer qui t'a manqué : intérieur d'abord, concret ensuite. Avec le temps, tu deviens une figure de sécurité pour les autres, précisément parce que tu sais ce que coûte son absence. Ta tendresse mûrie est la plus fiable qui soit.",
        leo: "Ta leçon de vie touche le rayonnement : être vu, créer, oser occuper le centre. Autant de choses qui n'ont jamais été simples pour toi. Tu as pu te sentir invisible, ou jugé dès que tu brillais, d'où un frein sur ta propre lumière. Saturne ici forge une créativité sérieuse et une légitimité gagnée : quand tu montes sur scène, c'est préparé, mérité, incontestable. Avec les années, tu apprends que ta valeur n'attend pas la validation. Ta maîtrise finale : rayonner sobrement, avec une autorité chaleureuse qui n'a plus peur d'elle-même.",
        virgo: "Ta leçon de vie touche le travail et la perfection : tu portes une exigence énorme sur ce que tu produis, parfois jusqu'au blocage. Rien ne semble jamais assez bien, à commencer par toi. La santé et l'hygiène de vie peuvent aussi être des terrains d'apprentissage. Saturne ici forge un artisan d'exception : rigueur, conscience professionnelle, excellence discrète. Avec le temps, tu apprends la différence entre exigence et maltraitance de soi. Ta maîtrise finale : faire très bien sans te détruire. Le service durable plutôt que le sacrifice.",
        libra: "Saturne est exalté en Balance : ta leçon de vie est l'engagement. Les relations sérieuses, les contrats, la justice : tu prends le lien plus au sérieux que la plupart des gens, quitte à hésiter longtemps avant de t'engager, ou à porter des relations comme des responsabilités. Saturne ici forge un partenaire d'une loyauté rare et un sens de l'équité qui fait de toi un arbitre naturel. Avec les années, tes liens gagnent ce que d'autres perdent : de la solidité. Ta maîtrise finale : des engagements choisis librement, tenus dignement.",
        scorpio: "Ta leçon de vie touche le contrôle et la confiance : l'intimité profonde, le partage du pouvoir, l'abandon. Autant de seuils difficiles. Tu as pu vivre des expériences où faire confiance s'est payé cher, d'où une vigilance de fond et une peur d'être vulnérable. Saturne ici forge une force psychique exceptionnelle : tu peux traverser des crises qui briseraient d'autres personnes. Avec le temps, tu apprends à lâcher sans te perdre. Ta maîtrise finale : une puissance tranquille qui n'a plus besoin de contrôler pour se sentir en sécurité.",
        sagittarius: "Ta leçon de vie touche le sens : croire, espérer, donner une direction à ton existence. Rien de tout cela ne t'a été livré clé en main. Tu t'es peut-être méfié tôt des credos tout faits, ou tu as cherché longtemps une vérité qui tienne. Saturne ici forge une foi bâtie, pas héritée : chaque conviction a été testée contre le réel. Avec les années, tu deviens un sage discret, quelqu'un dont la vision du monde a des fondations. Ta maîtrise finale : un optimisme adulte, qui connaît le prix des choses et espère quand même.",
        capricorn: "Saturne est chez lui en Capricorne : ta leçon de vie est la maîtrise elle-même. Responsabilité, réussite, endurance : tu portes tôt le poids des attentes, les tiennes en premier. Le risque : une vie entière convertie en devoir, où la joie attend toujours le prochain sommet. Saturne ici forge des bâtisseurs d'exception : ce que tu construis te survivra. Avec le temps, tu apprends que la structure sert la vie, pas l'inverse. Ta maîtrise finale : l'accomplissement et la douceur. Un sommet où l'on respire.",
        aquarius: "Ta leçon de vie touche la liberté et le groupe : trouver ta place dans le collectif sans t'y dissoudre, être différent sans être exclu. Tu as pu te sentir à part, ou responsable de causes plus grandes que toi. Saturne ici (son domicile traditionnel) forge une indépendance structurée : tes idées d'avance ont des plans, tes utopies des fondations. Avec les années, tu deviens un architecte du futur, pris au sérieux là où d'autres rêveurs sont ignorés. Ta maîtrise finale : libre et fiable à la fois. La rébellion devenue institution utile.",
        pisces: "Ta leçon de vie touche les frontières de l'âme : la sensibilité, l'intuition, la compassion. Autant de dons que tu as peut-être appris à brider, faute de savoir les contenir. Le flou t'inquiète : tu veux des preuves là où il n'y a que des signes. Saturne ici forge une spiritualité incarnée : ni fuite ni déni, mais une sagesse qui relie le ciel et le sol. Avec le temps, tu apprends à structurer ton monde intérieur sans le dessécher. Ta maîtrise finale : un mystique aux pieds sur terre. Le rêve devenu œuvre.",
    },

    Uranus: {
        aries: "Ton originalité s'exprime dans l'action : tu inventes en fonçant, tu libères en osant le geste que personne ne fait. Ta génération porte un courage de rupture ; chez toi, il devient un style : démarrer autrement, casser les codes du premier pas. Ton défi : que tes coups d'éclat servent une direction, pas seulement le frisson du nouveau.",
        taurus: "Ton originalité travaille la matière : tu réinventes le rapport aux ressources, à l'argent, au corps, à la terre. Ta génération bouscule les sécurités établies ; chez toi, cela donne un talent pour bâtir autrement : des valeurs neuves sur des fondations solides. Ton défi : accueillir les secousses qui libèrent, même quand elles touchent ton confort.",
        gemini: "Ton originalité passe par les idées : ta pensée fait des étincelles, connecte des mondes que rien ne reliait, parle une langue d'avance. Ta génération réinvente la communication ; chez toi, cela devient un esprit inclassable, brillant dans l'inattendu. Ton défi : canaliser cette électricité mentale pour qu'elle éclaire au lieu de seulement surprendre.",
        cancer: "Ton originalité touche l'intime : tu réinventes la famille, le foyer, la manière d'appartenir. Ta génération a libéré les modèles domestiques ; chez toi, cela donne le besoin d'un chez-soi qui ne ressemble à aucun autre. Ton défi : innover dans tes racines sans te couper d'elles. La liberté émotionnelle n'est pas l'absence d'attaches.",
        leo: "Ton originalité veut créer : ton expression personnelle sort des cadres. Art, style, manière de briller, tout y passe. Ta génération a électrisé la création ; chez toi, cela devient une signature unique, immédiatement reconnaissable. Ton défi : créer librement sans avoir besoin de choquer. Ta singularité suffit, elle n'a pas à se prouver.",
        virgo: "Ton originalité optimise : tu vois comment tout pourrait fonctionner mieux. Le travail, la santé, les systèmes du quotidien. Ta génération a révolutionné les méthodes ; chez toi, cela donne un génie pratique de l'amélioration, inventif dans le concret. Ton défi : accepter que l'humain ne s'optimise pas comme un logiciel. Le vivant a besoin de jeu.",
        libra: "Ton originalité réinvente le lien : couple, contrats, équilibres. Tu ne peux pas aimer ni t'associer selon les modèles reçus. Ta génération a libéré la relation ; chez toi, cela devient un besoin d'égalité réelle et d'espace dans l'engagement. Ton défi : innover dans le lien sans fuir l'engagement lui-même. La liberté à deux se construit, elle ne s'improvise pas.",
        scorpio: "Ton originalité plonge dans les tabous : tu libères ce qui est enfoui. Désirs, pouvoirs, vérités que ta génération a arrachés au silence. Chez toi, cela donne une capacité rare à transformer les crises en mutations éclair. Ton défi : maîtriser ce voltage intérieur pour régénérer plutôt que pour tout dynamiter. La rupture aussi peut être précise.",
        sagittarius: "Ton originalité vise les croyances : tu libères le sens. Religions, philosophies, visions du monde, rien n'échappe à ton examen. Ta génération a ouvert les esprits au monde entier ; chez toi, cela devient une quête de vérité affranchie des dogmes. Ton défi : rester chercheur sans devenir prêcheur d'anti-dogme. La liberté de croire inclut celle des autres.",
        capricorn: "Ton originalité s'attaque aux structures : institutions, hiérarchies, autorité. Tu vois ce qui est périmé et comment le rebâtir. Ta génération a ébranlé les pouvoirs établis ; chez toi, cela donne un talent d'architecte réformateur : casser proprement, reconstruire mieux. Ton défi : réformer avec patience. Les structures tombent vite, les alternatives se bâtissent lentement.",
        aquarius: "Uranus est chez lui en Verseau : ton originalité est au carré. Ta génération porte l'utopie collective (réseaux, technologies, fraternités nouvelles) ; chez toi, cela devient une identité de pionnier absolu, éveilleur né. Ton défi : garder un fil avec le présent et les gens tels qu'ils sont. Le futur se construit avec l'humanité réelle, pas seulement l'idéale.",
        pisces: "Ton originalité passe par l'invisible : intuition fulgurante, spiritualité libre, imaginaire sans frontières. Ta génération a dissous les cadres du sacré ; chez toi, cela donne un accès direct à l'inspiration : les idées te traversent plus que tu ne les fabriques. Ton défi : ancrer ces éclairs dans des formes durables, pour que la vision devienne œuvre et non mirage.",
    },

    Neptune: {
        aries: "Ton idéal se rêve en acte : ta génération porte le rêve du héros inspiré, de l'action qui aurait un sens sacré. Chez toi, cela donne le besoin que tes combats aient une âme. Ton défi : vérifier que la cause est réelle avant de t'y consumer. L'inspiration guide mieux qu'elle n'ordonne.",
        taurus: "Ton idéal cherche un paradis terrestre : ta génération rêve d'une abondance simple, d'un rapport enchanté à la nature et à la matière. Chez toi, cela donne un sens du beau presque mystique. Ton défi : ne pas idéaliser la sécurité au point de t'endormir dedans. Le paradis se cultive, il ne s'achète pas.",
        gemini: "Ton idéal passe par les mots : ta génération rêve d'une communication totale, d'un savoir qui relierait tout le monde. Chez toi, cela donne une pensée poétique, intuitive, inspirée. Ton défi : garder le sens critique. Quand tout se raconte bien, le vrai et le séduisant se confondent facilement.",
        cancer: "Ton idéal est un foyer parfait : ta génération porte la nostalgie d'une appartenance absolue. Famille rêvée, patrie intérieure, refuge originel. Chez toi, cela donne une tendresse immense pour les tiens. Ton défi : aimer ta famille réelle plutôt que celle du rêve, et bâtir un chez-toi qui existe ailleurs qu'en souvenir.",
        leo: "Ton idéal veut de la grandeur : ta génération rêve de gloire inspirée, de créations qui touchent au divin. Chez toi, cela donne un romantisme créatif puissant : l'art comme élévation. Ton défi : créer pour l'œuvre et non pour le mirage de la reconnaissance. La magie opère quand l'ego s'efface.",
        virgo: "Ton idéal cherche la pureté dans l'utile : ta génération rêve de guérison, de service parfait, d'un quotidien qui aurait du sens jusque dans les détails. Chez toi, cela donne une vocation d'aide presque religieuse. Ton défi : servir sans te dissoudre. Le dévouement a besoin de limites pour rester une force et non un sacrifice.",
        libra: "Ton idéal est l'amour parfait : ta génération rêve de l'âme sœur, de l'harmonie absolue, de la justice idéale. Chez toi, cela donne un romantisme raffiné et une soif de beauté dans les liens. Ton défi : aimer des personnes réelles. L'autre n'est pas un rêve à habiter mais un être à rencontrer.",
        scorpio: "Ton idéal plonge dans le mystère : ta génération a rêvé d'expériences limites, de fusion totale, de vérités cachées. Chez toi, cela donne une intuition des profondeurs hors du commun. Ton défi : explorer les abîmes sans t'y dissoudre. Les portes de la psyché s'ouvrent mieux avec un fil d'Ariane.",
        sagittarius: "Ton idéal cherche le sens ultime : ta génération rêve d'une vérité universelle, d'une spiritualité sans frontières. Chez toi, cela donne une foi intuitive, voyageuse, éprise d'absolu. Ton défi : accepter que la vérité se vive par fragments. Le doute fait partie du pèlerinage, pas de l'échec.",
        capricorn: "Ton idéal rêve de refonder les structures : ta génération a vu les institutions vaciller et porte le rêve d'un ordre plus juste. Chez toi, cela donne une ambition teintée d'idéal : réussir doit avoir un sens. Ton défi : bâtir tes rêves pierre par pierre, sans laisser le désenchantement saper le chantier.",
        aquarius: "Ton idéal est collectif : ta génération rêve d'une humanité reliée, fraternelle, éveillée. Chez toi, cela donne une vision inspirée du futur et des causes qui te dépassent. Ton défi : servir l'utopie sans mépriser le présent. L'humanité idéale commence par ton voisin réel.",
        pisces: "Neptune est chez lui en Poissons : ta génération porte un réenchantement du monde. Spiritualité, imaginaire, compassion sans frontières. Chez toi, l'accès à l'invisible est grand ouvert : inspiration, empathie, rêves marquants. Ton défi : des digues solides (discernement, ancrage, hygiène mentale) pour que l'océan te porte au lieu de te noyer.",
    },

    Pluto: {
        aries: "Ta puissance de transformation passe par l'affirmation : détruire les anciennes façons d'agir pour en inventer de plus vraies. Chez toi, la volonté est un volcan, capable de renaissances spectaculaires. Ton défi : que cette force serve à construire, pas à imposer.",
        taurus: "Ta puissance de transformation travaille la matière : ton rapport à l'argent, au corps, à la possession est appelé à changer en profondeur. Chez toi, les crises touchent la sécurité, et t'apprennent qu'elle est intérieure. Ton défi : lâcher pour recevoir davantage.",
        gemini: "Ta puissance de transformation passe par la pensée : les mots peuvent chez toi détruire ou régénérer. Ta génération a vu l'information devenir un pouvoir. Ton défi : utiliser ta lucidité verbale pour révéler, pas pour manipuler.",
        cancer: "Ta puissance de transformation touche les racines : famille, mémoire, appartenances. Ce qui est enfoui dans la lignée demande à être vu et guéri. Chez toi, l'émotion est une force tectonique. Ton défi : transformer l'héritage au lieu de le subir.",
        leo: "Ta puissance de transformation passe par la création et l'ego : mourir aux images de soi pour renaître plus vrai. Ta génération a réinventé l'expression individuelle. Ton défi : rayonner par authenticité, pas par besoin de puissance.",
        virgo: "Ta puissance de transformation travaille le quotidien : santé, travail, habitudes. Chez toi, la guérison est une œuvre de fond. Ta génération a transformé le rapport au corps et au service. Ton défi : perfectionner sans purger. L'humain n'est pas une erreur à corriger.",
        libra: "Ta puissance de transformation passe par la relation : tes liens profonds sont des creusets. On n'en sort pas indemne, on en sort transformé. Ta génération a refondé le couple. Ton défi : vivre l'intensité relationnelle sans jeux de pouvoir.",
        scorpio: "Pluton est chez lui en Scorpion : ta génération est née pour la métamorphose. Tabous levés, zones d'ombre affrontées, intensité assumée. Chez toi, la capacité de renaître est maximale : chaque crise te laisse plus vaste. Ton défi : apprivoiser ta propre puissance pour qu'elle régénère au lieu de consumer.",
        sagittarius: "Ta puissance de transformation touche les croyances : ta génération a vu les vérités officielles vaciller et cherche un sens qui résiste à l'examen. Chez toi, la quête est viscérale. Ton défi : détruire les dogmes sans brûler la foi. Il reste quelque chose après le doute.",
        capricorn: "Ta puissance de transformation s'attaque aux structures : ta génération assiste à la mue des pouvoirs, des institutions, des modèles de réussite. Chez toi, l'ambition porte une mission de refondation. Ton défi : incarner l'autorité autrement. Puissante parce que juste.",
        aquarius: "Ta puissance de transformation est collective : ta génération refonde le lien social lui-même. Réseaux, communautés, technologies du commun. Chez toi, l'appel à libérer est profond. Ton défi : mettre la puissance au service du nombre sans dissoudre l'individu.",
        pisces: "Ta puissance de transformation passe par la dissolution : ta génération verra changer le spirituel, l'imaginaire, l'invisible. Chez toi, la frontière entre soi et le tout est un lieu de métamorphose. Ton défi : te laisser transformer par plus grand que toi sans t'y perdre.",
    },

    Lilith: {
        aries: "Ta part sauvage vit dans l'affirmation brute : une volonté farouche, un désir d'exister sans permission. On a pu juger ta combativité excessive, te faire honte de ta colère ou de ton audace, et tu as peut-être appris à freiner cet élan. Mais cette rage de vivre est ta médecine : bien apprivoisée, elle devient un courage que rien n'intimide. Ta liberté commence le jour où tu cesses de t'excuser de vouloir.",
        taurus: "Ta part sauvage vit dans le corps et le plaisir : une sensualité profonde, un rapport instinctif à la matière, au désir, à la possession. On a pu te faire honte de tes appétits ou de ton attachement aux choses. Mais cette intensité sensorielle est ta médecine : assumée, elle devient une présence au monde d'une rare densité. Ta liberté commence quand tu savoures sans culpabilité ce que la vie t'offre.",
        gemini: "Ta part sauvage vit dans la parole : des pensées qui dérangent, des questions interdites, une langue qui refuse la censure. On a pu te faire taire, moquer tes idées, te trouver « trop » dans tes mots. Mais cette parole libre est ta médecine : assumée, elle nomme ce que tout le monde pense sans oser le dire. Ta liberté commence quand tu dis ta vérité sans adoucir ce qui n'a pas à l'être.",
        cancer: "Ta part sauvage vit dans l'émotionnel : des besoins immenses, une intensité affective qu'on a pu qualifier d'excessive. On t'a peut-être fait honte de ta sensibilité ou de ta façon d'aimer. Mais cette profondeur est ta médecine : assumée, elle devient une capacité de soin d'une puissance rare. Ta liberté commence quand tu accueilles tes besoins sans les juger indignes.",
        leo: "Ta part sauvage vit dans le rayonnement : un besoin d'être vu, une créativité flamboyante, une fierté qu'on a pu te reprocher comme de l'arrogance. Tu as peut-être appris à tamiser ta lumière pour ne pas déranger. Mais cet éclat est ta médecine : assumé, il autorise les autres à briller aussi. Ta liberté commence quand tu occupes ta place entière sans guetter la permission.",
        virgo: "Ta part sauvage vit dans un paradoxe : une exigence de pureté et de perfection qui peut devenir tyrannique, envers toi d'abord. On a pu te faire sentir jamais assez bien, jamais assez propre, jamais assez juste. Mais ce discernement radical est ta médecine : assumé, il voit ce que personne ne veut voir et répare ce que personne ne sait réparer. Ta liberté commence quand tu t'accordes le droit d'être imparfait sans être indigne.",
        libra: "Ta part sauvage vit dans le lien : un refus viscéral des relations inégales, des compromis qui effacent, des harmonies de façade. On a pu te trouver difficile parce que tu ne voulais pas d'un amour au rabais. Mais cette exigence relationnelle est ta médecine : assumée, elle crée des liens d'une vérité rare. Ta liberté commence quand tu préfères une solitude digne à une relation qui te diminue.",
        scorpio: "Ta part sauvage vit dans les profondeurs : un magnétisme, une intensité sexuelle et psychique, un accès aux tabous qu'on a pu te faire porter comme une étrangeté. Tu connais l'ombre : la tienne et celle des autres. Cette lucidité est ta médecine : assumée, elle transforme et guérit là où tout le monde détourne le regard. Ta liberté commence quand tu habites ta puissance sans en avoir peur.",
        sagittarius: "Ta part sauvage vit dans la liberté de croire : un refus des dogmes, une vérité personnelle qui ne rentre dans aucune église, une soif d'absolu indisciplinée. On a pu juger ta quête arrogante ou instable. Mais cette foi insoumise est ta médecine : assumée, elle ouvre des horizons que les cartes officielles ignorent. Ta liberté commence quand tu suis ta propre boussole sans demander si c'est permis.",
        capricorn: "Ta part sauvage vit dans l'ambition : une volonté de puissance qu'on t'a peut-être appris à cacher, un rapport à l'autorité fait de défi et de fascination. On a pu te faire honte de viser haut ou de vouloir diriger ta vie. Mais cette détermination est ta médecine : assumée, elle bâtit des œuvres que les prudents n'osent même pas rêver. Ta liberté commence quand tu assumes de vouloir réussir, à ta façon, selon tes règles.",
        aquarius: "Ta part sauvage vit dans la marge : une différence irréductible, un refus d'appartenir qui a pu te coûter l'exclusion ou l'étiquette de « bizarre ». Tu as peut-être appris à te normaliser pour être accepté. Mais cette étrangeté est ta médecine : assumée, elle libère tous ceux qui n'osaient pas être autres. Ta liberté commence quand tu cesses de négocier ta singularité contre de l'appartenance.",
        pisces: "Ta part sauvage vit dans l'invisible : une porosité psychique, des perceptions qu'on a pu traiter de folie douce, un refus des frontières que le monde exige. On t'a peut-être fait honte de rêver, de sentir, de croire. Mais cette porosité est ta médecine : assumée, elle fait de toi un canal (art, soin, spiritualité). Ta liberté commence quand tu honores tes perceptions sans attendre qu'on les valide.",
    },

    NorthNode: {
        aries: "Ta direction d'évolution : apprendre à exister par toi-même. Ton réflexe acquis (Nœud Sud en Balance) est de t'accorder aux autres, de maintenir l'harmonie, de te définir par la relation. La vie t'invite au mouvement inverse : oser vouloir, décider seul, déplaire s'il le faut. Chaque affirmation authentique, même maladroite, te fait grandir plus que mille compromis réussis. Ton cap : devenir quelqu'un avec qui l'on compte, pas seulement quelqu'un sur qui l'on compte.",
        taurus: "Ta direction d'évolution : apprendre la stabilité et la simplicité. Ton réflexe acquis (Nœud Sud en Scorpion) est l'intensité : crises, fusions, drames qui te sont étrangement familiers. La vie t'invite au calme : construire lentement, savourer le simple, faire confiance à ce qui dure. Chaque fois que tu choisis la paix plutôt que l'intensité, tu avances. Ton cap : découvrir que la profondeur peut être tranquille. La vraie richesse pousse dans un jardin, pas dans un volcan.",
        gemini: "Ta direction d'évolution : apprendre la curiosité et l'écoute. Ton réflexe acquis (Nœud Sud en Sagittaire) est de savoir déjà : convictions solides, vérités générales, leçons à transmettre. La vie t'invite à l'inverse : poser des questions, douter avec joie, t'intéresser au détail des gens réels. Chaque conversation où tu apprends au lieu d'enseigner te fait grandir. Ton cap : troquer la posture du sage contre celle de l'éternel étudiant. C'est là qu'est ta vraie sagesse.",
        cancer: "Ta direction d'évolution : apprendre la tendresse et l'appartenance. Ton réflexe acquis (Nœud Sud en Capricorne) est le contrôle : performer, assumer, porter sans rien demander. La vie t'invite à déposer l'armure : ressentir, avoir besoin, prendre soin et te laisser prendre en soin. Chaque moment de vulnérabilité choisie te fait grandir plus qu'un succès de plus. Ton cap : comprendre que le foyer que tu cherches à mériter t'est déjà ouvert. Il suffit d'y entrer.",
        leo: "Ta direction d'évolution : apprendre à briller en ton nom. Ton réflexe acquis (Nœud Sud en Verseau) est la distance : te fondre dans le groupe, théoriser, rester l'ami de tous et le centre de personne. La vie t'invite à descendre dans l'arène : créer, aimer, t'exposer personnellement. Chaque fois que tu signes ton œuvre au lieu de la dissoudre dans le collectif, tu avances. Ton cap : oser être spécial. Ton cœur a autant à dire que tes idées.",
        virgo: "Ta direction d'évolution : apprendre l'incarnation et le concret. Ton réflexe acquis (Nœud Sud en Poissons) est la fuite dans le vaste : rêve, spiritualité, sacrifice, flou protecteur. La vie t'invite à atterrir : un savoir-faire, des routines saines, un service précis rendu au réel. Chaque petite tâche accomplie avec soin te construit plus qu'une grande vision contemplée. Ton cap : faire de ta sensibilité un outil. Le divin est aussi dans les détails.",
        libra: "Ta direction d'évolution : apprendre l'autre. Ton réflexe acquis (Nœud Sud en Bélier) est de foncer seul : indépendance farouche, décisions solitaires, combat comme mode de vie. La vie t'invite au partenariat : écouter vraiment, coopérer, laisser l'autre compter. Chaque compromis librement consenti (par amour du lien, pas par peur) te fait grandir. Ton cap : découvrir qu'à deux, bien accordés, on va plus loin que ton élan seul ne l'aurait jamais permis.",
        scorpio: "Ta direction d'évolution : apprendre à lâcher. Ton réflexe acquis (Nœud Sud en Taureau) est de retenir : sécurités, possessions, habitudes, confort connu. La vie t'invite à la métamorphose : accepter les crises qui libèrent, partager le pouvoir, faire confiance sans garantie. Chaque attachement dépassé te rend plus vivant, pas plus pauvre. Ton cap : découvrir que ta vraie sécurité est ta capacité à renaître. Ce qui compte vraiment ne peut pas se perdre.",
        sagittarius: "Ta direction d'évolution : apprendre à croire. Ton réflexe acquis (Nœud Sud en Gémeaux) est de tout relativiser : mille informations, mille avis, une agilité mentale qui esquive l'engagement. La vie t'invite à choisir un cap : une vision, une foi, une direction qui donne sens au reste. Chaque fois que tu t'engages pour une vérité éprouvée au lieu de collectionner les points de vue, tu grandis. Ton cap : passer du commentaire au voyage. Le sens se trouve en chemin, pas dans les notes.",
        capricorn: "Ta direction d'évolution : apprendre la responsabilité de ta vie. Ton réflexe acquis (Nœud Sud en Cancer) est le refuge : famille, passé, dépendances affectives, l'enfance comme pays jamais vraiment quitté. La vie t'invite à grandir : viser, structurer, assumer ta place dans le monde. Chaque responsabilité embrassée sans te chercher d'excuse te libère. Ton cap : devenir ton propre parent. Solide, fiable, digne. L'autonomie est une tendresse envers soi.",
        aquarius: "Ta direction d'évolution : apprendre le collectif. Ton réflexe acquis (Nœud Sud en Lion) est la scène : briller, séduire, ramener l'histoire à soi. La vie t'invite à élargir : des causes plus grandes que ton nom, des amitiés d'égaux, une place dans le cercle plutôt qu'au centre. Chaque fois que ton talent sert le groupe sans réclamer la couronne, tu avances. Ton cap : découvrir que ta lumière ne diminue pas quand elle éclaire une œuvre commune. Elle se multiplie.",
        pisces: "Ta direction d'évolution : apprendre la confiance dans ce qui ne se contrôle pas. Ton réflexe acquis (Nœud Sud en Vierge) est le contrôle par le détail : analyser, corriger, t'inquiéter de tout ce qui pourrait clocher. La vie t'invite au lâcher-prise : intuition, compassion, acceptation de ce qui ne se maîtrise pas. Chaque fois que tu fais confiance au courant au lieu de vérifier chaque goutte, tu grandis. Ton cap : découvrir que la perfection que tu cherchais dans les détails t'attend dans le tout.",
    },
};


